// Inversion Excursion Website JavaScript - Optimized Version
// Performance improvements: throttled scroll, deferred loading, passive listeners

(function(){'use strict';var d=document,w=window,raf=w.requestAnimationFrame||function(cb){return setTimeout(cb,16)}, ticking=false;

// Mobile menu toggle
var menuToggle=d.querySelector('.menu-toggle'),sidebar=d.querySelector('.sidebar');
if(menuToggle&&sidebar){menuToggle.addEventListener('click',function(){sidebar.classList.toggle('open');});}

// Close sidebar when clicking outside on mobile
d.addEventListener('click',function(e){if(w.innerWidth<=768&&sidebar&&!sidebar.contains(e.target)&&!menuToggle.contains(e.target)){sidebar.classList.remove('open');}},{passive:true});

// Active nav link highlighting
var currentPage=w.location.pathname.split('/').pop(),navLinks=d.querySelectorAll('.nav-link');
navLinks.forEach(function(link){if(link.getAttribute('href').includes(currentPage)){link.classList.add('active');}});

// Smooth scroll for anchor links
d.querySelectorAll('a[href^="#"]').forEach(function(anchor){anchor.addEventListener('click',function(e){e.preventDefault();var target=d.querySelector(this.getAttribute('href'));if(target){target.scrollIntoView({behavior:'smooth',block:'start'});}});});

// Reading progress indicator - throttled
var progressBar=d.createElement('div');progressBar.className='reading-progress';progressBar.style.cssText='position:fixed;top:0;left:0;height:3px;background:var(--color-accent,#c9a227);width:0%;z-index:9999;transition:width .1s';d.body.appendChild(progressBar);

function updateProgress(){var winScroll=d.body.scrollTop||d.documentElement.scrollTop,height=d.documentElement.scrollHeight-d.documentElement.clientHeight,scrolled=height?(winScroll/height)*100:0;progressBar.style.width=scrolled+'%';ticking=false;}

w.addEventListener('scroll',function(){if(!ticking){raf(updateProgress);ticking=true;}},{passive:true});

// Keyboard shortcuts
d.addEventListener('keydown',function(e){if(e.key==='m'&&!e.ctrlKey&&!e.metaKey){if(w.innerWidth<=768&&sidebar){sidebar.classList.toggle('open');}}if(e.key==='Escape'&&sidebar){sidebar.classList.remove('open');}});

// Intersection Observer for fade-in animations
var observerOptions={root:null,rootMargin:'0px',threshold:.1},observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.style.opacity='1';entry.target.style.transform='translateY(0)';observer.unobserve(entry.target);}});},observerOptions);

// Observe sections for animation
d.querySelectorAll('.section,.chapter-card').forEach(function(el){el.style.opacity='0';el.style.transform='translateY(20px)';el.style.transition='opacity .6s ease,transform .6s ease';observer.observe(el);});
})();